import { Kernel, KernelPlugin, FunctionResult } from '@microsoft/semantic-kernel';
import { VexClient, RiskLevel, ValidationPolicy } from 'vex-sdk';

const vex = new VexClient({
  apiKey: process.env.VEX_API_KEY!,
  policies: [
    ValidationPolicy.PROMPT_INJECTION,
    ValidationPolicy.DATA_EXFILTRATION,
    ValidationPolicy.PLAN_VALIDATION,
  ],
});

// Implement auto-function-invocation filter for planner validation
async function vexAutoInvocationFilter(
  context: {
    chatHistory: any[];
    function: { pluginName: string; name: string };
    arguments: Record<string, unknown>;
    requestSequenceIndex: number;
    functionSequenceIndex: number;
    terminate: boolean;
    result?: FunctionResult;
  },
  next: () => Promise<void>
): Promise<void> {
  const { pluginName, name: functionName } = context.function;

  // Validate the planner's intent to call this function at this sequence index
  const planCheck = await vex.validatePlanStep({
    pluginName,
    functionName,
    stepIndex: context.functionSequenceIndex,
    sequenceIndex: context.requestSequenceIndex,
    arguments: context.arguments,
    chatHistory: context.chatHistory.map((m) => ({
      role: m.role,
      content: m.content,
    })),
    tags: ['semantic-kernel', 'auto-invocation', pluginName],
  });

  if (planCheck.riskLevel === RiskLevel.CRITICAL) {
    console.error(
      `[Vex] Blocked planner step ${pluginName}.${functionName}: ${planCheck.violationReason}`
    );
    context.terminate = true;
    return;
  }

  if (planCheck.riskLevel === RiskLevel.HIGH) {
    await vex.logIncident({
      incidentType: 'suspicious_plan_step',
      details: planCheck,
      plugin: pluginName,
      function: functionName,
    });
  }

  await next();

  // Post-execution: validate result for cross-plugin contamination
  if (context.result) {
    const outputCheck = await vex.validateOutput({
      payload: {
        plugin: pluginName,
        function: functionName,
        result: String(context.result.value),
      },
      contextId: `${pluginName}.${functionName}`,
      tags: ['semantic-kernel', 'auto-invocation-output'],
    });

    if (outputCheck.riskLevel === RiskLevel.CRITICAL) {
      context.terminate = true;
      await vex.logIncident({
        incidentType: 'output_contamination_detected',
        details: outputCheck,
        plugin: pluginName,
        function: functionName,
      });
    }
  }
}

export { vexAutoInvocationFilter };
